      //Filtros de la Experiencia
      checkPageReady()

      //Lanzamos la Experiencia
      .then(respuesta => renderVariant())

      //Control de errores: captura y traza
      .catch(err => {
          log2Con("Error!!! " + err.toString(), "error");
        });

    }

