  (function() {


    var testName = "T600 - [Des]Activador de nuevo flujo de pagos de desacople [BKI]";
    var variantName = "Control";
    var t600 = {};

    try {
    //Carga de configuración
    configLoad();

    //Validamos que estan las MNTTGFs
    wait4MNTTGF()
    //Si es así procedemos con la Variante y si no registramos el problema con MNTTGF
    .then(processVariant,falloMNTTGFLoad);

    } catch (err)
    {
        log2Con(err.toString(), "error");
    }

    //-----------------------------------------
    // CONFIGURACION DE LA VARIANTE
    //-----------------------------------------

    function configLoad() {

      // nivel de criticidad de los mensajes de consola
      t600.defaultLogLevel = "debug";
      //Para dejar trazas en el DOM
      // t600.defaultLogLevel = "info";
    }

    //-----------------------------------------
    // FILTROS Y PROCESADO DE LA VARIANTE
    //-----------------------------------------

    function processVariant () {

      //Filtros de la Experiencia
      checkPageReady()
      //Lanzamos la Experiencia
      .then(respuesta => renderVariant())

      //Control de errores: captura y traza
      .catch(err => {
          log2Con("Error!!! " + err.toString(), "error");
        });

    }

    /// functiones de propias de la variante
    ///////////////////////////////////////////////////////////////////////////////////////////////////////

    function renderVariant() {

      // Variant status definition
      ////////////////////////////

      // If at that point you are defining listener, observers, or other artifacts that doesn't change el original application behaviour,
      // report now the experience status as "OK - Waiting" and include a status change to "OK - Rendered" in the listener/observer definition

      //log2Con("OK - Waiting","warning");

      // If you are modifing the original application behaviour, then report as "OK - Rendered"

      log2Con("OK - Rendered","warning");
      log2GTM();

      // Your code here!!!
      ///////////////////////////////
      localStorage.removeItem("ib-booking-app.forcePaymentType");
      ///////////////////////////////

      log2Con("Fin de la variante","info");
    }

    /// functiones core del template
    ///////////////////////////////////////////////////////////////////////////////////////////////////////



    function wait4MNTTGF() {
      return new Promise(function(resolve,reject) {

        console.debug(new Date().toLocaleString("es-ES",{timeZoneName:"short"}) + " - [" + testName + "|" + variantName + "] - waiting 4 MNTTGF to load...");

        //Evaluamos si las MNTTGF se han cargado cada 100 milisegundos y si es así resolvemos la promesa
        setTimeout(() => {
          const intervalMNTTGF = setInterval(function() {
            if (window.mnttGF) {
              log2Con("MNTTGF running!! :)","info");
              clearInterval(intervalMNTTGF);
              clearTimeout(timeoutMGTTGF);
              resolve();
            } else if (window.mnttGF=="locked") {
              log2Con("ATTENTION!!!! MNTTGF LOCKED!!!!!!!!!!!!!!!!!!!!!!!!! :(","warning");
              clearInterval(intervalMNTTGF);
              clearTimeout(timeoutMGTTGF);
              resolve();
            } else if (window.mnttGF=="loading") {
              log2Con("loading MNTTGF... :|","info");
            }
          },100);

          //Si tras 10 segundos no se han cargado las MNTTGF rechazamos la promesa
          const timeoutMGTTGF = setTimeout(() => {
            clearInterval(intervalMNTTGF);
            reject();
          },10000);
        },0);


      });
    }

    function falloMNTTGFLoad() {
      timestamp = new Date().toLocaleString("es-ES",{timeZoneName:"short"});
      texto = "MNTTGF TIMEOUT!!!: No se ha cargado la experiencia MONETATE GLOBAL FUNCTIONS :(";
      aviso = timestamp + " [" + testName + "|" + variantName + "]:--> " + texto;

      console.error(aviso);

      avisoHTML='<div class="mnttgf_error">' + timestamp + ': ' + texto + '</div>';

      // lo metemos en el DOM para que lo registre QM

      if (document.getElementById("MNTT_LOGS")==null) {
        output = '<div data-nosnippet id="MNTT_LOGS" class="mnttgf_logs" style="display: none;"></div>';
        document.querySelector("body").insertAdjacentHTML("beforeend", output);
      }

      idText = (testName + '_' + variantName).trim();

      if (document.getElementById(idText) == null) {
        output = '<div id="' + idText + '" class="mnttgf_logs" style="display: none;">Monetate log: [' + testName + '][' + variantName + '] </div>';
        document.getElementById("MNTT_LOGS").insertAdjacentHTML("beforeend", output);
      }

      document.getElementById(idText).insertAdjacentHTML("beforeend",avisoHTML);
    }



    /// funciones proxy para MNTTGF
    /////////////////////////////////////////////

    function checkPageReady(pageCondition = function() {return true;}){
      return mnttCheckPageReady(testName,variantName,pageCondition);
    }

    function checkConditions(funcionCondicion,conditionDescription = "") {
      return mnttCheckConditions(testName,variantName,funcionCondicion,conditionDescription);
    }

    function checkTarget(target,currentValue,targetDescription = "") {
      return mnttCheckTarget(testName,variantName,target,currentValue,targetDescription);
    }

    function log2Con(texto,criticidad = "info") {
        mnttLog2Con(testName,variantName,texto,criticidad);
    }

    function obj2Con(objeto) {
        mnttObj2Con(testName,variantName,objeto);
    }

    function log2GTM(test = testName, action = variantName, value = "") {
        mnttLog2GTM(test,action,value);
    }

    function sendEventQM(eventNum,eventValue = "",eventDesc="")
    {
        mnttSendEventQM(testName,variantName,eventNum,eventValue,eventDesc);
    }

    /////////////////////////////////////////

  })();

