monetate.c.cr({"data": "/**************************************************************
 *  MNTTGF 3.9  04/2/2026
 **************************************************************
  - Fix digital_data en logging
 **************************************************************/
//# sourceURL=MNTTGF-3-9.js


if (!!window.MNTTGF3) {
  window.MNTTGF3.mnttLog2Con(window.MNTTGF3.MNTT_NAME,window.MNTTGF3.MNTT_VERSION,"Monetate: Global functions already loaded!!");
} else {

  window.MNTTGF3={};
  window.MNTTGF3.MNTT_STATUS="loading";
  window.MNTTGF3.MNTT_NAME="MNTTGF";
  window.MNTTGF3.MNTT_VERSION="3.9";
  window.MNTTGF3.MNTT_FULLNAME=window.MNTTGF3.MNTT_NAME+" "+window.MNTTGF3.MNTT_VERSION;
  window.MNTTGF3.MNTT_GTM_LOADED=false;
  window.MNTTGF3.MNTT_GTM_ACTIVE=true;

  /////////////////////////////////
  // Constantes
  /////////////////////////////////

  if (window.location.host.indexOf("www.iberia.com")>=0) {
    window.MNTTGF3.MNTT_DOMAIN="PROD";
    window.MNTTGF3.MNTT_REG_DOMAIN="";
    window.MNTTGF3.MNTT_LOGIN_DOMAIN="";
  } else if (window.location.host.indexOf("pre.iberia.com")>=0) {
    window.MNTTGF3.MNTT_DOMAIN="PREPROD";
    window.MNTTGF3.MNTT_REG_DOMAIN="";
    window.MNTTGF3.MNTT_LOGIN_DOMAIN="";
  } else if (window.location.host.indexOf("int.iberia.com")>=0) {
    window.MNTTGF3.MNTT_DOMAIN="INTEGRATON";
    window.MNTTGF3.MNTT_REG_DOMAIN="";
    window.MNTTGF3.MNTT_LOGIN_DOMAIN="";
  } else if (window.location.host.indexOf(".iberia.es")>=0) {
    window.MNTTGF3.MNTT_DOMAIN="PREPROD ONPREMISE";
    window.MNTTGF3.MNTT_REG_DOMAIN="";
    window.MNTTGF3.MNTT_LOGIN_DOMAIN="";
  }

  //Configuración trazas de log en consola
  window.MNTTGF3.MNTT_LOG = localStorage.getItem("MONETATE_LOG");

  // Fix para solventar el problema de la no existencia de window.jQuery
  // provocado por la nueva release de iberia.com con webpack

  timestamp = new Date().toLocaleString();
  console.debug(timestamp+ "[" + window.MNTTGF3.MNTT_FULLNAME + "] Fixing JQuery=$");
  window.MNTTGF3.counterJQuery = 0;
  window.MNTTGF3.intervalJQuery = setInterval(function() {
    if (typeof($) == "function" && typeof($()) == "object") {
        jQuery = $;
      clearInterval(window.MNTTGF3.intervalJQuery);
    }
    if (window.MNTTGF3.counterJQuery++ > 30) {
      timestamp = new Date().toLocaleString();
      console.error(timestamp+ "[" + window.MNTTGF3.MNTT_FULLNAME + "] JQuery no definido por la aplicacion en 3 segundos!! (timeout error)");
      clearInterval(window.MNTTGF3.intervalJQuery);
    }
  }, 100);

  /*
  function jQuery(comando) {
    mnttLog2QM("")
  }*/
  /////////////////////////////////
  // Funciones analítica
  /////////////////////////////////



    // Funciones de QM
  window.MNTTGF3.mnttSendEventQM = function (eventAction, eventLabel, eventNumber, eventValue = "", eventDesc="") {
    var counter = 0;
    var descr = "";
    var eventTimeStamp=new Date().toISOString();
    var CurrentQuadrigam=(!!window.digital_data && !!window.digital_data.Quadrigam)?window.digital_data.Quadrigam:"";

    if (typeof(window.MNTTGF3.MNTT_QM)=="undefined" || window.MNTTGF3.MNTT_QM!=false ){
      if (typeof eventValue == "string" || typeof eventValue == "number"){

        if (eventDesc == "")
          descr=eventNumber;
        else
          descr=eventDesc;

        if (typeof eventValue == "string")
          eventValue=eventValue.replaceAll(/(^\s+|\s+$|\s+(?=\s))/g, "");

        if (!!window.QuantumMetricAPI && !!window.QuantumMetricAPI.sendEvent) {
          window.QuantumMetricAPI.sendEvent(eventNumber, 0 , eventValue);

          if (eventNumber=="69") {
            //Disparamos tb el evento de variante con atributos
            var atributosEvento={
              Value: eventValue,
              ExperienceName: eventAction,
              VariantName: eventLabel,
              Description: eventDesc,
              TimeStamp: eventTimeStamp,
              Quadrigam: CurrentQuadrigam,
              URL: location.pathname,
            };
            window.QuantumMetricAPI.sendEvent("845",0,eventValue,atributosEvento);
          }

          window.MNTTGF3.mnttLog2Con(eventAction,eventLabel,"Tracking QM[" + descr + "]: done! ("+counter+")","debug");
        } else {
          var intervalQM = setInterval(function() {
            if (!!window.QuantumMetricAPI && !!window.QuantumMetricAPI.sendEvent) {
                window.QuantumMetricAPI.sendEvent(eventNumber, 0, eventValue);
                window.MNTTGF3.mnttLog2Con(eventAction,eventLabel,"Tracking QM[" + descr + "]: done! ("+counter+")","debug");
                if (eventNumber=="69") {
                  //Disparamos tb el evento de variante con atributos
                  var atributosEvento={
                    Value: eventValue,
                    ExperienceName: eventAction,
                    VariantName: eventLabel,
                    Description: eventDesc,
                    TimeStamp: eventTimeStamp,
                    Quadrigam: CurrentQuadrigam,
                    URL: location.pathname,
                  };
                  window.QuantumMetricAPI.sendEvent("845",0,eventValue,atributosEvento);
                }
                window.MNTTGF3.MNTT_QM=true;
                clearInterval(intervalQM);
            } else if (counter++ > 10 ) {
                window.MNTTGF3.mnttLog2Con(eventAction,eventLabel,"Tracking QM[" + descr + "]: Timeout - QuantumMetricAPI no disponible","info");
                window.MNTTGF3.MNTT_QM=false;
                clearInterval(intervalQM);

            } else if (!!window.MNTTGF3.mnttGetCookie("OptanonConsent") && window.MNTTGF3.mnttGetCookie("OptanonConsent").indexOf("&interactionCount=0")>=0 ) {
                window.MNTTGF3.mnttLog2Con(eventAction,eventLabel,"Tracking QM[" + descr + "]: Tracking Cookies pendiente de confirmar.","info");
                counter--;

            } else if (!!window.MNTTGF3.mnttGetCookie("OptanonConsent") && window.MNTTGF3.mnttGetCookie("OptanonConsent").indexOf("&interactionCount=0")<0 && window.MNTTGF3.mnttGetCookie("OptanonConsent").indexOf("C0002:1")<0 ) {
                window.MNTTGF3.mnttLog2Con(eventAction,eventLabel,"Tracking QM[" + descr + "]: Tracking Cookies Rejected - QuantumMetricAPI no disponible","info");
                window.MNTTGF3.MNTT_QM=false;
                clearInterval(intervalQM);
            }
          }, 3000);
        }
      } else {
        window.MNTTGF3.mnttLog2Con(eventAction,eventLabel,"Tracking QM[" + descr + "]: el EventValue es un tipo de dato invalido","warning");
      }
    }
  };


  // Funciones para compatibilidad con templates antiguos
  window.MNTTGF3.mnttLog2TL=function(testName, variantName) {};
  window.MNTTGF3.mnttError2TL=function (testName, variantName) {};

  // Envio de eventos a los sistemas de analisis: GA4, QM

  window.MNTTGF3.mnttGFprocessLog2GADeferred=function()
  {

    //defino un listener para controlar el abandono de la página con eventos por enviar
    window.addEventListener("unload", function() {
      if (!!window.MNTTGF3.mnttGF_log2GA_Offline) {
        localStorage.setItem("mnttGF_log2GA_Offline",JSON.stringify(window.MNTTGF3.mnttGF_log2GA_Offline));
      }
    });

    //Si existen eventos offline en el localStorare procesarlos
    if (!!localStorage.getItem("mnttGF_log2GA_Offline") && localStorage.getItem("mnttGF_log2GA_Offline")!="undefined") {

      window.MNTTGF3.mnttLog2Con(window.MNTTGF3.MNTT_NAME,window.MNTTGF3.MNTT_VERSION,"Eventos Offline detectados!!");
      window.MNTTGF3.mnttGF_log2GA_Deferred_Offline=JSON.parse(localStorage.getItem("mnttGF_log2GA_Offline"));
      window.MNTTGF3.mnttGF_log2GA_Deferred_Offline.forEach(function (evento) {
        window.MNTTGF3.mnttLog2GTM(evento.eventAction,evento.eventLabel,evento.timeStamp,evento.Quadrigam,"Offline");
      } );
      localStorage.removeItem("mnttGF_log2GA_Offline");
      window.MNTTGF3.mnttGF_log2GA_Deferred_Offline=undefined;
    }

    //Si existen eventos deferred en el localStorare procesarlos
    if (!!localStorage.getItem("mnttGF_log2GA_Deferred") && localStorage.getItem("mnttGF_log2GA_Deferred")!="undefined") {

      window.MNTTGF3.mnttLog2Con(window.MNTTGF3.MNTT_NAME,window.MNTTGF3.MNTT_VERSION,"Eventos Deferred detectados!!");
      window.MNTTGF3.mnttGF_log2GA_Deferred=JSON.parse(localStorage.getItem("mnttGF_log2GA_Deferred"));
      window.MNTTGF3.mnttGF_log2GA_Deferred.forEach(function (evento) {
        window.MNTTGF3.mnttLog2GTM(evento.eventAction,evento.eventLabel,evento.timeStamp,evento.Quadrigam,"Offline");
      } );
      localStorage.removeItem("mnttGF_log2GA_Deferred");
      window.MNTTGF3.mnttGF_log2GA_Deferred=undefined;
    }

  };

  window.MNTTGF3.mnttGFProcessLog2GAOffline=function()
  {
    if (!window.MNTTGF3.mnttGF_log2GA_Offline || window.MNTTGF3.mnttGF_log2GA_Offline.length==0) {
      window.MNTTGF3.mnttGFProcessLog2GAOfflineActive=false;
      window.MNTTGF3.mnttGF_log2GA_Offline=undefined;
      window.MNTTGF3.mnttLog2Con(window.MNTTGF3.MNTT_NAME,window.MNTTGF3.MNTT_VERSION,"Sin eventos Offline.. pausamos procesamiento");
    } else {

      if (!window.MNTTGF3.mnttGFProcessLog2GAOfflineActive) {
        window.MNTTGF3.mnttLog2Con(window.MNTTGF3.MNTT_NAME,window.MNTTGF3.MNTT_VERSION,"Eventos Offline detectados!! Activamos procesamiento");
        window.MNTTGF3.mnttGFProcessLog2GAOfflineActive=true;
      }
      evento=window.MNTTGF3.mnttGF_log2GA_Offline.shift();
      window.MNTTGF3.mnttLog2GA40(evento.eventAction,evento.eventLabel,evento.eventTimeStamp,evento.eventQuadrigam);

      setTimeout(window.MNTTGF3.mnttGFProcessLog2GAOffline,100);
    }
  };

  window.MNTTGF3.mnttLog2GTM=function (eventAction, eventLabel, eventMode = "Offline") {


    window.MNTTGF3.mnttLog2Con(eventAction,eventLabel,"Tracking GA, GA40 & QM...","debug");

    var eventTimeStamp=new Date().toISOString();
    var eventQuadrigam=(!!window.digital_data && !!window.digital_data.Quadrigam)?window.digital_data.Quadrigam:"";

    //Envio de eventos a GA4
    switch (eventMode) {

      case "Online":
        //Envio Online o inmediato

        //Envio de eventos a QM
        window.MNTTGF3.mnttLog2QM(eventAction,eventLabel);
        window.MNTTGF3.mnttLog2Con(eventAction,eventLabel,"Tracking QM Online: sent!","info");

        //envio de evento a GA4
        window.MNTTGF3.mnttLog2GA40(eventAction,eventLabel,eventTimeStamp,eventQuadrigam);
        window.MNTTGF3.mnttLog2Con(eventAction,eventLabel,"Tracking GA4 Online: sent!","info");
        break;

      case "Deferred":
        //Envio Deferred para que se procese en la siguiente página
        if (!window.MNTTGF3.mnttGF_log2GA_Deferred) {
          window.MNTTGF3.mnttGF_log2GA_Deferred = [];
        }
        if (!!localStorage.getItem("mnttGF_log2GA_Deferred")) {
          window.MNTTGF3.mnttGF_log2GA_Deferred=JSON.parse(localStorage.getItem("mnttGF_log2GA_Deferred"));
        }
        window.MNTTGF3.mnttGF_log2GA_Deferred.push({eventAction: eventAction, eventLabel: eventLabel, eventTimeStamp: eventTimeStamp, eventQuadrigam: eventQuadrigam});
        localStorage.setItem("mnttGF_log2GA_Deferred",JSON.stringify(window.MNTTGF3.mnttGF_log2GA_Deferred));

        window.MNTTGF3.mnttLog2Con(eventAction,eventLabel,"Tracking QM/GA4 Deferred: done","info");
        break;

      default:
        //envio Offline que es el que se procesa poco a poco en GA4 sin sobrecarga de eventos

        //Envio de eventos a QM
        window.MNTTGF3.mnttLog2Con(eventAction,eventLabel,new Date().toISOString() + " - Tracking QM Online: sent!","info");
        window.MNTTGF3.mnttLog2QM(eventAction,eventLabel);

        //envio de evento a GA4
        if (!window.MNTTGF3.mnttGF_log2GA_Offline) {
          window.MNTTGF3.mnttGF_log2GA_Offline = [];
        }
        window.MNTTGF3.mnttGF_log2GA_Offline.push({eventAction: eventAction, eventLabel: eventLabel, eventTimeStamp: eventTimeStamp, eventQuadrigam: eventQuadrigam});
        window.MNTTGF3.mnttLog2Con(eventAction,eventLabel,new Date().toISOString() + " - Tracking GA4 Offline: done","info");
        if (!window.MNTTGF3.mnttGFProcessLog2GAOfflineActive) {
          window.MNTTGF3.mnttGFProcessLog2GAOffline();
        }
        break;
    }

  };





  // Envia hits a GA40
  window.MNTTGF3.mnttLog2GA40=function (eventAction, eventLabel, eventTimeStamp="", eventQuadrigam=""){
    var counter = 0;
    var GA4_digital_data = {};
    var eventName = "MNTTGF2GA4";

    if (window.MNTTGF3.MNTT_GTM_ACTIVE) {
      GA4_digital_data = {
        'eventCategory': eventName,
        'eventAction': eventAction,
        'eventLabel': eventLabel,
        'eventName': eventName
        };


      var intervalGA4 = setInterval(function() {

        if (window.MNTTGF3.MNTT_GTM_LOADED || (!!window.dataLayer && window.dataLayer.some(item => item.event === "gtm.dom"))) {
          window.dataLayer.push(GA4_digital_data,{'event':'interaction'});
          window.MNTTGF3.MNTT_GTM_LOADED=true;
          window.MNTTGF3.mnttLog2Con(eventAction,eventLabel,new Date().toISOString() + " - Tracking GA40: sent! ("+eventTimeStamp+")","info");
          clearInterval(intervalGA4);
        } else if (counter++ > 30) {
          window.MNTTGF3.MNTT_GTM_ACTIVE=false;
